    kids = " ".join(f"{pid} 0 R" for pid in page_ids)
    pages_content = f"<< /Type /Pages /Kids [{kids}] /Count {len(page_ids)} >>"
    pages_bytes = f"2 0 obj\n{pages_content}\nendobj\n".encode("latin-1")
