    buf += f"<< /Size {len(objects) + 1} /Root {catalog_id} 0 R >>\n".encode("ascii")
    buf += b"startxref\n"
    buf += f"{xref_offset}\n".encode("ascii")
    buf += b"%%EOF\n"
