def normalize_work_text(text: object, status: str = "") -> str:
    s = re.sub(r"\s+", " ", str(text or "")).strip()
    if not s:
        return ""
    s = re.sub(r"^\[[ x>\-]\]\s*", "", s, flags=re.IGNORECASE)
    s = re.sub(
        r"^(pending|in[_\-\s]?progress|completed|done|blocked)\s*[·:\-\]]\s*",
        "",
        s,
        flags=re.IGNORECASE,
    )
    if status:
        status_pattern = re.escape(status).replace("_", r"[_\-\s]?")
        s = re.sub(
            rf"\s*[—-]\s*{status_pattern}\s*$",
            "",
            s,
            flags=re.IGNORECASE,
        )
    s = re.sub(
        r"\s*[—-]\s*(pending|in[_\-\s]?progress|completed|done|blocked)\s*$",
        "",
        s,
        flags=re.IGNORECASE,
    )
    return s.strip(" -")

def parse_front_matter(text: str) -> tuple[dict, str]:
    text = text or ""
    # Strip leading HTML/XML comments (kimi-agent-internals format)
    stripped = text
    while stripped.lstrip().startswith("<!--"):
        end_comment = stripped.find("-->")
        if end_comment < 0:
            break
        stripped = stripped[end_comment + 3:].lstrip()
    # Standard YAML frontmatter: ---\n...\n---\n
    if stripped.startswith("---\n"):
        end = stripped.find("\n---\n", 4)
        if end < 0:
            # Try alternate ending: \n--- followed by EOF or \n--\n
            end = stripped.find("\n---", 4)
            if end >= 0 and (end + 4 >= len(stripped) or stripped[end + 4] in ('\n', '\r', ' ')):
                raw_meta = stripped[4:end]
                body = stripped[end + 4:].strip()
            else:
                return {}, text.strip()
        else:
            raw_meta = stripped[4:end]
            body = stripped[end + 5:].strip()
    # Kimi xlsx format: no --- delimiters, but starts with "name:" and "description:"
    elif re.match(r'\s*name\s*:', stripped):
        # Find where the frontmatter-like section ends (blank line, markdown heading, XML tag, or bare --)
        lines = stripped.splitlines()
        meta_end = 0
        for i, line in enumerate(lines):
            s = line.strip()
            if s == "" or s.startswith("#") or s.startswith("<") or s in ("--", "---"):
                meta_end = i
                break
        else:
            meta_end = min(5, len(lines))
        raw_meta = "\n".join(lines[:meta_end])
        body = "\n".join(lines[meta_end:]).strip()
    else:
        return {}, text.strip()

    def _normalize_front_matter_value(value: object):
        if isinstance(value, dict):
            out: dict[str, object] = {}
            for key, row in value.items():
                out[str(key)] = _normalize_front_matter_value(row)
            return out
        if isinstance(value, list):
            return [_normalize_front_matter_value(x) for x in value]
        if value is None or isinstance(value, (str, int, float, bool)):
            return value
        return str(value)

    def _parse_scalar(raw: str):
        txt = str(raw or "").strip()
        if not txt:
            return ""
        if len(txt) >= 2 and txt[0] == txt[-1] and txt[0] in {"'", '"'}:
            return txt[1:-1]
        low = txt.lower()
        if low == "true":
            return True
        if low == "false":
            return False
        if low in {"null", "none"}:
            return ""
        if re.fullmatch(r"-?\d+", txt):
            try:
                return int(txt)
            except Exception:
                return txt
        if re.fullmatch(r"-?\d+\.\d+", txt):
            try:
                return float(txt)
            except Exception:
                return txt
        return txt

    def _parse_simple_yaml_block(raw: str) -> dict:
        lines = str(raw or "").splitlines()

        def _indent_of(line: str) -> int:
            return len(line) - len(line.lstrip(" "))

        def _next_significant(start: int):
            j = start
            while j < len(lines):
                if lines[j].strip():
                    return j
                j += 1
            return len(lines)

        def _parse_block(start: int, indent: int):
            j = _next_significant(start)
            if j >= len(lines):
                return {}, j
            stripped = lines[j].strip()
            is_list = stripped.startswith("- ")
            if is_list:
                items: list[object] = []
                i = j
                while i < len(lines):
                    if not lines[i].strip():
                        i += 1
                        continue
                    cur_indent = _indent_of(lines[i])
                    if cur_indent < indent:
                        break
                    if cur_indent != indent or not lines[i].lstrip().startswith("- "):
                        break
                    item_txt = lines[i].lstrip()[2:].strip()
                    i += 1
                    if not item_txt:
                        nested, i = _parse_block(i, indent + 2)
                        items.append(nested)
                        continue
                    if item_txt.endswith(":") and ":" not in item_txt[:-1]:
                        nested, i = _parse_block(i, indent + 2)
                        items.append({item_txt[:-1].strip(): nested})
                        continue
                    if ":" in item_txt and not item_txt.startswith(("'", '"')):
                        key, rest = item_txt.split(":", 1)
                        rest = rest.strip()
                        if rest:
                            items.append({key.strip(): _parse_scalar(rest)})
                            continue
                        nested, i = _parse_block(i, indent + 2)
                        items.append({key.strip(): nested})
                        continue
                    items.append(_parse_scalar(item_txt))
                return items, i

            obj: dict[str, object] = {}
            i = j
            while i < len(lines):
                if not lines[i].strip():
                    i += 1
                    continue
                cur_indent = _indent_of(lines[i])
                if cur_indent < indent:
                    break
                if cur_indent != indent:
                    break
                stripped_line = lines[i].strip()
                if ":" not in stripped_line:
                    i += 1
                    continue
                key, rest = stripped_line.split(":", 1)
                key = key.strip()
                rest = rest.strip()
                i += 1
                if rest in {"|", ">"}:
                    block_lines: list[str] = []
                    while i < len(lines):
                        if not lines[i].strip():
                            block_lines.append("")
                            i += 1
                            continue
                        next_indent = _indent_of(lines[i])
                        if next_indent <= cur_indent:
                            break
                        block_lines.append(lines[i][cur_indent + 2 :] if len(lines[i]) >= cur_indent + 2 else "")
                        i += 1
                    if rest == ">":
                        folded = " ".join(x.strip() for x in block_lines if x.strip())
                        obj[key] = folded.strip()
                    else:
                        obj[key] = "\n".join(block_lines).strip()
                    continue
                if rest:
                    obj[key] = _parse_scalar(rest)
                    continue
                nested, i = _parse_block(i, cur_indent + 2)
                obj[key] = nested
            return obj, i

        parsed, _ = _parse_block(0, 0)
        return parsed if isinstance(parsed, dict) else {}

    if _yaml is not None:
        try:
            parsed = _yaml.safe_load(raw_meta)
            if isinstance(parsed, dict):
                return _normalize_front_matter_value(parsed), body
        except Exception:
            pass

    meta = _parse_simple_yaml_block(raw_meta)
    return _normalize_front_matter_value(meta), body

def make_unified_diff(path: str, old_text: str, new_text: str, max_lines: int = 400) -> tuple[str, int, int]:
    old_lines = old_text.splitlines()
    new_lines = new_text.splitlines()
    diff = list(
        difflib.unified_diff(
            old_lines,
            new_lines,
            fromfile=f"a/{path}",
            tofile=f"b/{path}",
            lineterm="",
        )
    )
    added = sum(1 for ln in diff if ln.startswith("+") and not ln.startswith("+++"))
    deleted = sum(1 for ln in diff if ln.startswith("-") and not ln.startswith("---"))
    if max_lines and len(diff) > max_lines:
        diff = diff[:max_lines] + [f"... diff truncated, total lines={len(diff)}"]
    text = "\n".join(diff) if diff else f"@@ no textual diff for {path}"
    return text, added, deleted

def _skip_row(text: str) -> dict:
    msg = str(text or "").strip() or "⋮"
    if not msg.startswith("⋮"):
        msg = f"⋮ {msg}"
    return {"kind": "skip", "sign": "⋮", "old_line": None, "new_line": None, "text": msg}

def _row_is_hot(row: dict) -> bool:
    return str((row or {}).get("kind", "")).strip().lower() in {"add", "delete"}

def _hotspot_index(rows: list[dict]) -> int:
    arr = [dict(x) for x in (rows or [])]
    if not arr:
        return 0
    hot = [1 if _row_is_hot(row) else 0 for row in arr]
    if not any(hot):
        return max(0, len(arr) - 1)
    prefix = [0]
    for v in hot:
        prefix.append(prefix[-1] + v)
    n = len(arr)
    radius = max(10, min(180, n // 18))
    best_idx = 0
    best_score = -1
    for i in range(n):
        a = max(0, i - radius)
        b = min(n - 1, i + radius)
        score = prefix[b + 1] - prefix[a]
        if score > best_score or (score == best_score and i > best_idx):
            best_idx = i
            best_score = score
    return best_idx

def _compress_rows_keep_hotspot(
    rows: list[dict],
    max_rows: int,
    *,
    prefix_omitted: int = 0,
) -> tuple[list[dict], bool]:
    arr = [dict(x) for x in (rows or [])]
    limit = max(1, int(max_rows or 1))
    omitted_prefix_base = max(0, int(prefix_omitted or 0))
    if not arr:
        if omitted_prefix_base <= 0:
            return [], False
        return [_skip_row(f"⋮ ... ({omitted_prefix_base} rows omitted)")], True
    anchor = _hotspot_index(arr)
    n = len(arr)
    slots = (1 if omitted_prefix_base > 0 else 0) + 1
    slots = min(limit - 1, max(0, slots))
    start = 0
    end = n
    for _ in range(3):
        budget = max(1, limit - slots)
        if budget >= n:
            start, end = 0, n
        else:
            start = max(0, anchor - (budget // 2))
            if start + budget > n:
                start = max(0, n - budget)
            end = min(n, start + budget)
        omitted_prefix = omitted_prefix_base + start
        omitted_suffix = max(0, n - end)
        new_slots = (1 if omitted_prefix > 0 else 0) + (1 if omitted_suffix > 0 else 0)
        new_slots = min(limit - 1, max(0, new_slots))
        if new_slots == slots:
            break
        slots = new_slots
    omitted_prefix = omitted_prefix_base + start
    omitted_suffix = max(0, n - end)
    out: list[dict] = []
    if omitted_prefix > 0:
        out.append(_skip_row(f"⋮ ... ({omitted_prefix} rows omitted)"))
    out.extend(arr[start:end])
    if omitted_suffix > 0:
        out.append(_skip_row(f"⋮ ... ({omitted_suffix} rows omitted)"))
    truncated = omitted_prefix > 0 or omitted_suffix > 0
    if len(out) > limit:
        out = out[:limit]
        truncated = True
    return out, truncated

def make_numbered_diff(old_text: str, new_text: str, max_lines: int = 320) -> list[dict]:
    old_lines = old_text.splitlines()
    new_lines = new_text.splitlines()
    sm = difflib.SequenceMatcher(a=old_lines, b=new_lines)
    entries: list[dict] = []
    max_lines = max(16, int(max_lines or 320))
    # Keep bounded memory on huge files while preserving latest/hot rows.
    buffer_cap = max(max_lines + 256, min(6_000, max_lines * 6))
    dropped_head = 0

    def _push(row: dict):
        nonlocal dropped_head
        entries.append(row)
        if len(entries) <= buffer_cap:
            return
        drop = len(entries) - buffer_cap
        del entries[:drop]
        dropped_head += drop

    for tag, i1, i2, j1, j2 in sm.get_opcodes():
        if tag == "equal":
            for off in range(i2 - i1):
                _push(
                    {
                        "kind": "context",
                        "sign": " ",
                        "old_line": i1 + off + 1,
                        "new_line": j1 + off + 1,
                        "old_col": 1,
                        "new_col": 1,
                        "text": old_lines[i1 + off],
                    }
                )
        elif tag == "delete":
            for idx in range(i1, i2):
                _push(
                    {
                        "kind": "delete",
                        "sign": "-",
                        "old_line": idx + 1,
                        "new_line": None,
                        "old_col": 1,
                        "new_col": None,
                        "text": old_lines[idx],
                    }
                )
        elif tag == "insert":
            for idx in range(j1, j2):
                _push(
                    {
                        "kind": "add",
                        "sign": "+",
                        "old_line": None,
                        "new_line": idx + 1,
                        "old_col": None,
                        "new_col": 1,
                        "text": new_lines[idx],
                    }
                )
        elif tag == "replace":
            for idx in range(i1, i2):
                _push(
                    {
                        "kind": "delete",
                        "sign": "-",
                        "old_line": idx + 1,
                        "new_line": None,
                        "old_col": 1,
                        "new_col": None,
                        "text": old_lines[idx],
                    }
                )
            for idx in range(j1, j2):
                _push(
                    {
                        "kind": "add",
                        "sign": "+",
                        "old_line": None,
                        "new_line": idx + 1,
                        "old_col": None,
                        "new_col": 1,
                        "text": new_lines[idx],
                    }
                )
    out, _ = _compress_rows_keep_hotspot(entries, max_lines, prefix_omitted=dropped_head)
    return out

def render_numbered_diff_text(entries: list[dict]) -> str:
    out = []
    for row in entries:
        if row.get("kind") == "skip":
            out.append(f"    {str(row.get('text') or '⋮').strip()}")
            continue
        old_ln = row.get("old_line")
        new_ln = row.get("new_line")
        ln = old_ln if old_ln is not None else new_ln
        sign = row.get("sign", " ")
        text = row.get("text", "")
        out.append(f"{str(ln or ''):>6} {sign} {text}")
    return "\n".join(out)

